24	      const amuletResult = runScenario({
25	        customer: { yearsWithMHPCO: 0 },
26	        steps: [{ op: "quote", items: [{ type: "amulet" }] }],
27	      });
28	      const staffResult = runScenario({
29	        customer: { yearsWithMHPCO: 0 },
30	        steps: [{ op: "quote", items: [{ type: "staff" }] }],
31	      });
