103	    it("should form one block per component type: 3 runes + 3 moonstones give base premium 120", () => {
104	      const result = runScenario({
105	        customer: { yearsWithMHPCO: 0 },
106	        steps: [
107	          {
108	            op: "quote",
109	            items: [
