139	    it("should not add the enchantment surcharge for enchantment level 4", () => {
140	      const result = runScenario({
141	        customer: { yearsWithMHPCO: 0 },
142	        steps: [{ op: "quote", items: [{ type: "sword", enchantment: 4 }] }],
143	      });
144	
145	      expect(result.results[0].premium).toBe(115);
146	    });
147	    it("should stack curse and enchantment surcharges on one item", () => {
148	      const result = runScenario({
149	        customer: { yearsWithMHPCO: 0 },
150	        steps: [
