167	    it("should apply the 20% loyalty discount for yearsWithMHPCO exactly 2", () => {
168	      const result = runScenario({
169	        customer: { yearsWithMHPCO: 2 },
170	        steps: [{ op: "quote", items: [{ type: "sword" }] }],
171	      });
172	
173	      expect(result.results[0].premium).toBe(95);
174	    });
175	    it.todo("should apply the 10% first-insurance surcharge to every quote");
176	    it.todo("should apply the 15% follow-up discount to each quote after the first");
177	    it.todo("should round the final premium up to whole gold (197.5 becomes 198)");
178	    it.todo("should quote 165 for a newcomer (0 years) with a cursed steel sword of enchantment 3");
179	    it.todo("should quote 160 for a 3-year customer's second quote with a cursed sword of enchantment 7");
180	  });
181	
182	  describe("Claim payout", () => {
183	    it.todo("should subtract the 100 deductible from the damage amount: regular sword (enchantment 3) damaged 500 pays out 400");
184	    it.todo("should apply the deductible per damaged item, not per incident: sword 500 + amulet 300 pay out 600");
185	    it.todo("should reimburse 50% of the damage for enchantment level 9 or higher than 8 (steel sword enchantment 9), before the deductible");
186	    it.todo("should reimburse dragon-material items in full: dragon sword enchantment 5 gets full reimbursement");
187	    it.todo("should let the 50% rule win when dragon material and enchantment 8 combine: dragon sword enchantment exactly 8, damage 1000 pays out 400");
188	    it.todo("should treat components as having no enchantment or material: rune damaged 200 pays out 100");
189	    it.todo("should return remainingCap as 2x the insurance sum minus payouts: sword + amulet have insurance sum 1600 and cap 3200");
190	    it.todo("should keep the insurance sum unmodified by the block discount: sword + 3 runes have insurance sum 1750");
191	    it.todo("should sum same-type items into the insurance sum: two swords have insurance sum 2000 and cap 4000");
192	    it.todo("should consume the cap across successive claims: sword (cap 2000) with two claims of 1500 pays 1400 then 600");
193	    it.todo("should round the final payout down to whole gold (350.5 becomes 350)");
194	    it.todo("should apply a separate deductible per damage entry for two insured swords");
195	  });
196	
197	  describe("Errors", () => {
198	    it.todo("should reject a quote containing an unknown item type (broomstick)");
199	    it.todo("should reject a claim damage entry whose item type is not in the policy (amulet damaged, only sword insured)");
200	    it.todo("should reject a claim with more damage entries of a type than items insured (two sword damages, one sword insured)");
201	    it.todo("should reject a claim damage entry with an unknown item type");
202	    it.todo("should reject a negative damage amount");
203	  });
204	
205	  describe("CLI", () => {
206	    it.todo("should read a JSON scenario from stdin and write {results: [...]} to stdout with exit code 0");
207	    it.todo("should exit non-zero with the error on stderr and no results on stdout for an invalid scenario");
208	  });
209	});
